BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?signal ?signalType ?signalName ?diagram ?diagramName WHERE {
  ?recycleBin vocab:NamedElement_name "_TMT_RecycleBin" .

  # Signals contained under the recycle bin
  ?recycleBin (vocab:Element_ownedElement|vocab:Package_packagedElement|vocab:Namespace_member|vocab:Namespace_ownedMember|vocab:Package_ownedType)+ ?signal .

  ?signal rdf:type ?signalType .
  FILTER(
    ?signalType IN (
      vocab:Signal,
      vocab:SignalEvent,
      vocab:Reception
    )
  )
  OPTIONAL { ?signal vocab:NamedElement_name ?signalName . }

  # Active diagrams that reference these signals
  ?diagram rdf:type vocab:view .
  OPTIONAL {
    ?diagram vocab:NamedElement_name ?diagramName .
  }

  # Use diagram context as the anchor, and then traverse to signal usage via messages/events.
  ?diagram vocab:Diagram_context ?ctx .
  ?ctx (vocab:Element_ownedElement+|vocab:Package_packagedElement+|vocab:Namespace_member+|vocab:Namespace_ownedMember+) ?usedMessage .
  ?usedMessage rdf:type vocab:Message .

  OPTIONAL { ?usedMessage vocab:receiveEvent ?recvEvent . }
  OPTIONAL { ?usedMessage vocab:sendEvent ?sendEvent . }

  # If either receiveEvent or sendEvent is associated with a Signal/SigEvent/Reception matching our signal node.
  FILTER(
    EXISTS { ?usedMessage vocab:receiveEvent ?recvEvent .
             ?recvEvent (vocab:Event_behavior|vocab:Reception_signal|vocab:SignalEvent_signal|vocab:Reception_signal)? ?signal . }
    ||
    EXISTS { ?usedMessage vocab:sendEvent ?sendEvent .
             ?sendEvent (vocab:Event_behavior|vocab:SignalEvent_signal)? ?signal . }
    ||
    ?signal = ?recvEvent || ?signal = ?sendEvent
    ||
    EXISTS { ?signal rdf:type vocab:Signal .
             ?recvEvent vocab:Reception_signal ?signal . }
  )
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?signal ?signalType ?signalName WHERE {
  ?recycleBin vocab:NamedElement_name "_TMT_RecycleBin" .

  ?recycleBin (vocab:Element_ownedElement|vocab:Package_packagedElement|vocab:Namespace_member|vocab:Namespace_ownedMember|vocab:Package_ownedType)+ ?signal .
  ?signal rdf:type ?signalType .

  FILTER(
    ?signalType IN (vocab:Signal, vocab:SignalEvent, vocab:Reception)
  )
  OPTIONAL { ?signal vocab:NamedElement_name ?signalName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?child ?childType ?childName WHERE {
  ?recycleBin vocab:NamedElement_name "_TMT_RecycleBin" .

  ?recycleBin (vocab:Element_ownedElement|vocab:Package_packagedElement|vocab:Namespace_member|vocab:Namespace_ownedMember|vocab:Package_ownedType)+ ?child .
  ?child rdf:type ?childType .
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?sendAction ?sendActionName ?signal ?signalType ?signalName ?diagram ?diagramName WHERE {
  ?recycleBin vocab:NamedElement_name "_TMT_RecycleBin" .

  # find send-signal actions contained under recycle bin
  ?recycleBin (vocab:Element_ownedElement|vocab:Package_packagedElement|vocab:Namespace_member|vocab:Namespace_ownedMember|vocab:Package_ownedType)+ ?sendAction .
  ?sendAction rdf:type vocab:SendSignalAction .
  OPTIONAL { ?sendAction vocab:NamedElement_name ?sendActionName . }

  # associated signal
  ?sendAction vocab:SendSignalAction_signal ?signal .
  OPTIONAL { ?signal rdf:type ?signalType . }
  OPTIONAL { ?signal vocab:NamedElement_name ?signalName . }

  # active diagrams that reference the signal (via context traversal and message/event nodes)
  ?diagram rdf:type vocab:view .
  OPTIONAL { ?diagram vocab:NamedElement_name ?diagramName . }
  ?diagram vocab:Diagram_context ?ctx .
  ?ctx (vocab:Element_ownedElement+|vocab:Package_packagedElement+|vocab:Namespace_member+)+ ?msgOrEvent .

  # message/event links to signal
  {
    ?msgOrEvent rdf:type vocab:SignalEvent .
    ?msgOrEvent vocab:SignalEvent_signal ?signal .
  }
  UNION
  {
    ?msgOrEvent rdf:type vocab:Message .
    OPTIONAL { ?msgOrEvent vocab:receiveEvent ?recvEvent . }
    OPTIONAL { ?msgOrEvent vocab:sendEvent ?sendEvent . }
    {
      ?recvEvent rdf:type vocab:SignalEvent .
      ?recvEvent vocab:SignalEvent_signal ?signal .
    }
    UNION
    {
      ?sendEvent rdf:type vocab:SignalEvent .
      ?sendEvent vocab:SignalEvent_signal ?signal .
    }
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?sendAction ?sendActionName ?pred ?obj ?objName WHERE {
  ?recycleBin vocab:NamedElement_name "_TMT_RecycleBin" .

  ?recycleBin (vocab:Element_ownedElement|vocab:Package_packagedElement|vocab:Namespace_member|vocab:Namespace_ownedMember|vocab:Package_ownedType)+ ?sendAction .
  ?sendAction rdf:type vocab:send%20signal%20action .

  OPTIONAL { ?sendAction vocab:NamedElement_name ?sendActionName . }

  ?sendAction ?pred ?obj .
  OPTIONAL { ?obj vocab:NamedElement_name ?objName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?signal ?signalName ?diagram ?diagramName WHERE {
  ?recycleBin vocab:NamedElement_name "_TMT_RecycleBin" .
  ?recycleBin (vocab:Element_ownedElement|vocab:Package_packagedElement|vocab:Namespace_member|vocab:Namespace_ownedMember|vocab:Package_ownedType)+ ?sendAction .
  ?sendAction rdf:type vocab:send%20signal%20action .
  ?sendAction vocab:SendSignalAction_signal ?signal .

  OPTIONAL { ?signal vocab:NamedElement_name ?signalName . }

  # Find messages/signalevents that use the same signal
  ?interaction rdf:type vocab:Interaction .
  ?interaction vocab:message ?message .
  ?message rdf:type vocab:Message .
  OPTIONAL { ?message vocab:receiveEvent ?recvEvent . }
  OPTIONAL { ?message vocab:sendEvent ?sendEvent . }

  {
    ?recvEvent rdf:type vocab:signal%20event .
    ?recvEvent vocab:SignalEvent_signal ?signal .
  }
  UNION
  {
    ?sendEvent rdf:type vocab:signal%20event .
    ?sendEvent vocab:SignalEvent_signal ?signal .
  }

  # Active diagrams that reference the interaction
  ?diagram rdf:type vocab:view .
  OPTIONAL { ?diagram vocab:NamedElement_name ?diagramName . }
  ?diagram vocab:Diagram_context ?ctx .
  ?ctx (vocab:Element_ownedElement+|vocab:Package_packagedElement+|vocab:Namespace_member+)+ ?interaction .
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?diagram ?diagramType ?diagramName WHERE {
  ?diagram rdf:type ?diagramType .
  FILTER(?diagramType IN (vocab:Diagram, vocab:view))
  OPTIONAL { ?diagram vocab:NamedElement_name ?diagramName . }
} 
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?diagram ?diagramName ?pred ?objType WHERE {
  ?diagram rdf:type vocab:view .
  OPTIONAL { ?diagram vocab:NamedElement_name ?diagramName . }
  FILTER(CONTAINS(STR(?diagramName), "Hardware%20Decomposition%20and%20Interfaces"))
  ?diagram ?pred ?obj .
  OPTIONAL { ?obj rdf:type ?objType . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?diagram ?diagramName ?message ?messageName WHERE {
  BIND(<http://api.koneksys.com/cameo/TMT/signal/_TMT_RecycleBin::01%20signals::APS-Internal::signal_SelectFilter_Ack> AS ?signal)

  ?message rdf:type vocab:Message .

  # message receives or sends events that are signal events linked to our signal
  {
    ?message vocab:receiveEvent ?recvEvent .
    ?recvEvent rdf:type vocab:signal%20event .
    ?recvEvent vocab:SignalEvent_signal ?signal .
  }
  UNION
  {
    ?message vocab:sendEvent ?sendEvent .
    ?sendEvent rdf:type vocab:signal%20event .
    ?sendEvent vocab:SignalEvent_signal ?signal .
  }

  ?diagram rdf:type vocab:view .
  OPTIONAL { ?diagram vocab:NamedElement_name ?diagramName . }
  OPTIONAL { ?message vocab:NamedElement_name ?messageName . }

  ?diagram vocab:Element_ownedElement+ ?message .
}
LIMIT 25
